
'use client';

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { Calendar, Monitor, User, Clock } from 'lucide-react';
import { Attendance } from '@/utils/storage';
import { getAttendancesAction } from '@/app/actions/dbActions';

export default function MySessions() {
  const { user } = useAuth();
  const [sessions, setSessions] = useState<Attendance[]>([]);
  
  useEffect(() => {
    if (user) {
      loadSessions();
    }
  }, [user]);

  const loadSessions = async () => {
    if(!user) return;
    const allAttendances: Attendance[] = await getAttendancesAction();
    const mySessions = allAttendances.filter((s:any) => s.studentId === user.id);
    setSessions(mySessions.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  return (
    <div>
      <h2 className="text-3xl mb-2">My Sessions</h2>
      <p className="text-gray-600 mb-8">View your lab usage history</p>

      {sessions.length === 0 ? (
        <div className="bg-white rounded-xl shadow-lg p-12 text-center">
          <Calendar size={64} className="mx-auto mb-4 text-gray-300" />
          <p className="text-gray-500 text-lg">No sessions yet.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {sessions.map((session) => (
            <div
              key={session.id}
              className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-shadow"
            >
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <h3 className="text-xl mb-2 flex items-center gap-2">
                    <Monitor size={20} className="text-[#b40000]" />
                    {session.subjectId}
                  </h3>
                  <p className="text-gray-600 mb-1 flex items-center gap-2">
                    <User size={16} />
                    Teacher: Unknown
                  </p>
                  <p className="text-gray-600 mb-1">
                    Lab: Unknown - PC: Unknown
                  </p>
                  <p className="text-sm text-gray-500 flex items-center gap-2">
                    <Clock size={14} />
                    {new Date(session.date).toLocaleString()} - {session.timeOut ? new Date(session.timeOut).toLocaleString() : 'Active'}
                  </p>
                </div>
                <div className="text-right">
                  <span className={`px-4 py-2 rounded-full text-sm ${session.timeOut ? 'bg-gray-100 text-gray-800' : 'bg-blue-100 text-blue-800'}`}>
                    {session.timeOut ? 'Ended' : 'Active'}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
