
'use client';

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { Book, User, Calendar, Clock } from 'lucide-react';
import { getEnrollmentsAction, getSubjectsAction, getAttendancesAction } from '@/app/actions/dbActions';
import { Subject, Enrollment, Attendance } from '@/utils/storage';

export default function MySubjects() {
  const { user } = useAuth();
  const [subjects, setSubjects] = useState<any[]>([]);

  useEffect(() => {
    if(user) loadSubjects();
  }, [user]);

  const loadSubjects = async () => {
    if(!user) return;
    const enrollments: Enrollment[] = await getEnrollmentsAction();
    const allSubjects: Subject[] = await getSubjectsAction();
    const allAttendances: Attendance[] = await getAttendancesAction();

    const approved = enrollments.filter(
      (e: any) => e.studentId === user.id && e.status === 'approved'
    );
    
    const subjectData = approved.map((enrollment) => {
      const subject = allSubjects.find(s => s.id === enrollment.subjectId);
      if(!subject) return null;
      
      const sessions = allAttendances.filter(
        (a: any) => a.studentId === user.id && a.subjectId === subject.id
      );

      const lastSession = sessions.length > 0 ? sessions.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0] : null;

      return {
        ...enrollment,
        name: subject.name,
        teacherName: subject.teacherName,
        day: subject.day,
        startTime: subject.startTime,
        dismissalTime: subject.dismissalTime,
        sessionsCount: sessions.length,
        lastSession: lastSession?.date || null
      };
    }).filter(Boolean);

    setSubjects(subjectData);
  };

  return (
    <div>
      <h2 className="text-3xl mb-2">My Subjects</h2>
      <p className="text-gray-600 mb-8">View all your approved subject enrollments</p>

      {subjects.length === 0 ? (
        <div className="bg-white rounded-xl shadow-lg p-12 text-center">
          <Book size={64} className="mx-auto mb-4 text-gray-300" />
          <p className="text-gray-500 text-lg">Wala kang approved enrollments.</p>
        </div>
      ) : (
        <div className="grid gap-6">
          {subjects.map((subject) => (
            <div
              key={subject.id}
              className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-shadow cursor-pointer"
            >
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <h3 className="text-2xl mb-2 text-[#b40000] flex items-center gap-2">
                    <Book size={24} />
                    {subject.name}
                  </h3>
                  <p className="text-gray-600 flex items-center gap-2 mb-2">
                    <User size={18} />
                    {subject.teacherName}
                  </p>
                </div>
                <div className="text-right">
                  <div className="bg-green-100 text-green-800 px-4 py-2 rounded-full text-sm mb-2">
                    {subject.sessionsCount} Sessions
                  </div>
                  {subject.lastSession && (
                    <p className="text-xs text-gray-500">
                      Last: {new Date(subject.lastSession).toLocaleDateString()}
                    </p>
                  )}
                </div>
              </div>

              {subject.day && (
                <div className="border-t pt-4 mt-4">
                  <h4 className="text-sm mb-3 flex items-center gap-2">
                    <Calendar size={16} />
                    Schedules
                  </h4>
                  <div className="flex flex-wrap gap-2">
                      <div
                        className="bg-gray-100 px-3 py-2 rounded-lg text-sm flex items-center gap-2"
                      >
                        <Clock size={14} />
                        {subject.day} {subject.startTime}-{subject.dismissalTime}
                      </div>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
